var COURSE_SQ_TR = [{day: 1, title: `Përshëndetje dhe fjalët e para`, title_native: `Selamlaşma ve ilk kelimeler`, focus: `Sot mëson bazat për të përshëndetur njerëzit në Stamboll, Ankara ose Izmir. Këto shprehje të ndihmojnë në hotel, dyqan, kafene dhe në rrugë.`, vocab: [{tr: `merhaba`, sq: `përshëndetje`, ipa: `/mer-ha-ba/`},{tr: `selam`, sq: `tungjatjeta`, ipa: `/se-lam/`},{tr: `günaydın`, sq: `mirëmëngjes`, ipa: `/gy-naj-dën/`},{tr: `iyi akşamlar`, sq: `mirëmbrëma`, ipa: `/i-ji ak-sham-lar/`},{tr: `iyi geceler`, sq: `natën e mirë`, ipa: `/i-ji ge-xhe-ler/`},{tr: `hoşça kal`, sq: `mirupafshim`, ipa: `/hosh-ça kal/`},{tr: `teşekkürler`, sq: `faleminderit`, ipa: `/te-shek-kyr-ler/`},{tr: `lütfen`, sq: `ju lutem`, ipa: `/lyt-fen/`},{tr: `evet`, sq: `po`, ipa: `/e-vet/`},{tr: `hayır`, sq: `jo`, ipa: `/ha-jër/`}], phrases: [{tr: `Merhaba.`, sq: `Përshëndetje.`, ipa: `/mer-ha-ba/`},{tr: `Günaydın.`, sq: `Mirëmëngjes.`, ipa: `/gy-naj-dën/`},{tr: `Teşekkürler.`, sq: `Faleminderit.`, ipa: `/te-shek-kyr-ler/`},{tr: `Lütfen.`, sq: `Ju lutem.`, ipa: `/lyt-fen/`},{tr: `Hoşça kal.`, sq: `Mirupafshim.`, ipa: `/hosh-ça kal/`},{tr: `Evet, teşekkürler.`, sq: `Po, faleminderit.`, ipa: `/e-vet te-shek-kyr-ler/`}], grammar: `Në turqisht, një fjalë mund të përdoret shpesh pa ndryshime në situata të ndryshme. “Merhaba” është e sigurt dhe e sjellshme pothuajse kudo. “Selam” është më joformale, prandaj përdore me njerëz të rinj ose në situata miqësore.`, practice: [`Thuaj “Merhaba” sikur po hyn në një kafene në Stamboll.`,`Përkthe në turqisht: “Faleminderit.”`,`Zgjidh shprehjen më të sjellshme për një recepsion hoteli: “selam” apo “merhaba”.`,`Thuaj “Mirëmbrëma” në turqisht.`,`Krijo një mini-dialog me “Merhaba” dhe “Teşekkürler”.`]},{day: 2, title: `Prezantimi i vetes`, title_native: `Kendini tanıtma`, focus: `Në Ankara ose Stamboll, shpesh do të duhet të thuash emrin dhe nga vjen. Sot mëson si të prezantohesh thjesht dhe me siguri.`, vocab: [{tr: `ben`, sq: `unë`, ipa: `/ben/`},{tr: `sen`, sq: `ti`, ipa: `/sen/`},{tr: `ad`, sq: `emër`, ipa: `/ad/`},{tr: `benim adım`, sq: `emri im është`, ipa: `/be-nim a-dëm/`},{tr: `nereli`, sq: `nga ku`, ipa: `/ne-re-li/`},{tr: `Arnavutluk`, sq: `Shqipëria`, ipa: `/ar-na-vut-luk/`},{tr: `Türkiye`, sq: `Turqia`, ipa: `/tyr-ki-je/`},{tr: `turist`, sq: `turist`, ipa: `/tu-rist/`},{tr: `öğrenci`, sq: `student`, ipa: `/œj-ren-xhi/`},{tr: `memnun`, sq: `i kënaqur`, ipa: `/mem-nun/`}], phrases: [{tr: `Benim adım Arben.`, sq: `Emri im është Arben.`, ipa: `/be-nim a-dëm ar-ben/`},{tr: `Senin adın ne?`, sq: `Si quhesh ti?`, ipa: `/se-nin a-dën ne/`},{tr: `Ben Arnavutluk’tanım.`, sq: `Unë jam nga Shqipëria.`, ipa: `/ben ar-na-vut-luk-ta-nëm/`},{tr: `Ben turistim.`, sq: `Unë jam turist.`, ipa: `/ben tu-ris-tim/`},{tr: `Memnun oldum.`, sq: `Më vjen mirë.`, ipa: `/mem-nun ol-dum/`},{tr: `Türkiye’ye ilk kez geliyorum.`, sq: `Po vij në Turqi për herë të parë.`, ipa: `/tyr-ki-je-je ilk kez ge-li-jo-rum/`}], grammar: `Në turqisht “jam” shpesh shprehet me prapashtesë. “Turistim” do të thotë “jam turist”. Për vendet përdoret shpesh “-tan/-ten” për “nga”, si te “Arnavutluk’tanım”.`, practice: [`Prezanto veten me “Benim adım...”.`,`Thuaj në turqisht: “Unë jam nga Shqipëria.”`,`Pyet dikë si quhet në turqisht.`,`Thuaj “Më vjen mirë” pas një prezantimi.`,`Krijo 3 fjali me “ben”.`]},{day: 3, title: `Pyetje bazë dhe përgjigje të shkurtra`, title_native: `Temel sorular ve kısa cevaplar`, focus: `Në udhëtim, pyetjet e thjeshta të shpëtojnë kohë. Sot mëson si të pyesësh “çfarë”, “ku” dhe “a ka”.`, vocab: [{tr: `ne`, sq: `çfarë`, ipa: `/ne/`},{tr: `nerede`, sq: `ku`, ipa: `/ne-re-de/`},{tr: `kim`, sq: `kush`, ipa: `/kim/`},{tr: `nasıl`, sq: `si`, ipa: `/na-sël/`},{tr: `var`, sq: `ka, ekziston`, ipa: `/var/`},{tr: `yok`, sq: `nuk ka`, ipa: `/jok/`},{tr: `burada`, sq: `këtu`, ipa: `/bu-ra-da/`},{tr: `orada`, sq: `atje`, ipa: `/o-ra-da/`},{tr: `tamam`, sq: `në rregull`, ipa: `/ta-mam/`},{tr: `problem`, sq: `problem`, ipa: `/prob-lem/`}], phrases: [{tr: `Bu ne?`, sq: `Çfarë është kjo?`, ipa: `/bu ne/`},{tr: `Tuvalet nerede?`, sq: `Ku është tualeti?`, ipa: `/tu-va-let ne-re-de/`},{tr: `Burada Wi-Fi var mı?`, sq: `A ka Wi-Fi këtu?`, ipa: `/bu-ra-da waj-faj var më/`},{tr: `Evet, var.`, sq: `Po, ka.`, ipa: `/e-vet var/`},{tr: `Hayır, yok.`, sq: `Jo, nuk ka.`, ipa: `/ha-jër jok/`},{tr: `Tamam, teşekkürler.`, sq: `Në rregull, faleminderit.`, ipa: `/ta-mam te-shek-kyr-ler/`}], grammar: `Pyetja “var mı?” do të thotë “a ka?”. Fjala “mı/mi/mu/mü” vendoset pas fjalës kryesore për të krijuar pyetje. Mos u shqetëso për harmoninë e zanoreve tani; fillo duke njohur modelin.`, practice: [`Pyet në turqisht: “Ku është tualeti?”`,`Përgjigju “Po, ka” në turqisht.`,`Thuaj “Çfarë është kjo?” në një treg lokal.`,`Krijo një pyetje me “nerede”.`,`Krijo një pyetje me “var mı”.`]},{day: 4, title: `Numrat 0–20`, title_native: `0’dan 20’ye sayılar`, focus: `Numrat janë thelbësorë për çmime, bileta, dhoma hoteli dhe porosi. Sot mëson numrat e parë që do t’i përdorësh çdo ditë në Turqi.`, vocab: [{tr: `sıfır`, sq: `zero`, ipa: `/së-fër/`},{tr: `bir`, sq: `një`, ipa: `/bir/`},{tr: `iki`, sq: `dy`, ipa: `/i-ki/`},{tr: `üç`, sq: `tre`, ipa: `/yç/`},{tr: `dört`, sq: `katër`, ipa: `/dœrt/`},{tr: `beş`, sq: `pesë`, ipa: `/besh/`},{tr: `altı`, sq: `gjashtë`, ipa: `/all-të/`},{tr: `yedi`, sq: `shtatë`, ipa: `/je-di/`},{tr: `sekiz`, sq: `tetë`, ipa: `/se-kiz/`},{tr: `dokuz`, sq: `nëntë`, ipa: `/do-kuz/`}], phrases: [{tr: `Bir çay lütfen.`, sq: `Një çaj, ju lutem.`, ipa: `/bir çaj lyt-fen/`},{tr: `İki bilet lütfen.`, sq: `Dy bileta, ju lutem.`, ipa: `/i-ki bi-let lyt-fen/`},{tr: `Üç kişi.`, sq: `Tre persona.`, ipa: `/yç ki-shi/`},{tr: `Beş dakika.`, sq: `Pesë minuta.`, ipa: `/besh da-ki-ka/`},{tr: `On lira.`, sq: `Dhjetë lira.`, ipa: `/on li-ra/`},{tr: `Yirmi lira mı?`, sq: `Njëzet lira?`, ipa: `/jir-mi li-ra më/`}], grammar: `Numrat në turqisht vendosen para emrit dhe zakonisht emri mbetet në njëjës: “iki bilet”, jo “iki biletler”. Kjo është shumë praktike për udhëtarin sepse struktura mbetet e thjeshtë.`, practice: [`Numëro nga 1 deri në 10 në turqisht.`,`Thuaj “Dy bileta, ju lutem.”`,`Thuaj “Pesë minuta” në turqisht.`,`Pyet “Njëzet lira?”.`,`Krijo një porosi me një numër dhe një pije.`]},{day: 5, title: `Numrat 20–100 dhe çmimet`, title_native: `20’den 100’e sayılar ve fiyatlar`, focus: `Në pazare, dyqane dhe stacione, duhet të kuptosh çmimet. Sot mëson si të dëgjosh dhe të thuash shuma të thjeshta në lira turke.`, vocab: [{tr: `yirmi`, sq: `njëzet`, ipa: `/jir-mi/`},{tr: `otuz`, sq: `tridhjetë`, ipa: `/o-tuz/`},{tr: `kırk`, sq: `dyzet`, ipa: `/kërk/`},{tr: `elli`, sq: `pesëdhjetë`, ipa: `/el-li/`},{tr: `altmış`, sq: `gjashtëdhjetë`, ipa: `/alt-mësh/`},{tr: `yetmiş`, sq: `shtatëdhjetë`, ipa: `/jet-mish/`},{tr: `seksen`, sq: `tetëdhjetë`, ipa: `/sek-sen/`},{tr: `doksan`, sq: `nëntëdhjetë`, ipa: `/dok-san/`},{tr: `yüz`, sq: `njëqind`, ipa: `/jyz/`},{tr: `lira`, sq: `lira`, ipa: `/li-ra/`}], phrases: [{tr: `Bu kaç lira?`, sq: `Sa lira kushton kjo?`, ipa: `/bu kaç li-ra/`},{tr: `Otuz lira.`, sq: `Tridhjetë lira.`, ipa: `/o-tuz li-ra/`},{tr: `Çok pahalı.`, sq: `Shumë e shtrenjtë.`, ipa: `/çok pa-ha-lë/`},{tr: `Biraz indirim var mı?`, sq: `A ka pak zbritje?`, ipa: `/bi-raz in-di-rim var më/`},{tr: `Elli lira olur mu?`, sq: `A bëhet pesëdhjetë lira?`, ipa: `/el-li li-ra o-lur mu/`},{tr: `Tamam, alıyorum.`, sq: `Në rregull, po e marr.`, ipa: `/ta-mam a-lë-jo-rum/`}], grammar: `“Kaç” do të thotë “sa” kur pyesim për numër ose çmim. “Bu kaç lira?” është një nga pyetjet më të dobishme për tregje dhe dyqane. “Olur mu?” është mënyrë e sjellshme për të pyetur nëse diçka pranohet.`, practice: [`Thuaj në turqisht: “Sa lira kushton kjo?”`,`Përkthe: “Otuz lira.”`,`Krijo një fjali me “çok pahalı”.`,`Thuaj “A ka pak zbritje?”.`,`Bëj një dialog të shkurtër për blerjen e një suveniri.`]},{day: 6, title: `Ditët, ora dhe koha`, title_native: `Günler, saat ve zaman`, focus: `Kur rezervon tren, muze ose restorant në Stamboll, duhet të flasësh për kohën. Sot mëson fjalë për ditët dhe orarin.`, vocab: [{tr: `bugün`, sq: `sot`, ipa: `/bu-gyn/`},{tr: `yarın`, sq: `nesër`, ipa: `/ja-rën/`},{tr: `dün`, sq: `dje`, ipa: `/dyn/`},{tr: `sabah`, sq: `mëngjes`, ipa: `/sa-bah/`},{tr: `öğleden sonra`, sq: `pasdite`, ipa: `/œj-le-den son-ra/`},{tr: `akşam`, sq: `mbrëmje`, ipa: `/ak-sham/`},{tr: `saat`, sq: `ora`, ipa: `/sa-at/`},{tr: `dakika`, sq: `minutë`, ipa: `/da-ki-ka/`},{tr: `pazartesi`, sq: `e hënë`, ipa: `/pa-zar-te-si/`},{tr: `pazar`, sq: `e diel`, ipa: `/pa-zar/`}], phrases: [{tr: `Saat kaç?`, sq: `Sa është ora?`, ipa: `/sa-at kaç/`},{tr: `Saat üç.`, sq: `Është ora tre.`, ipa: `/sa-at yç/`},{tr: `Bugün açık mı?`, sq: `A është hapur sot?`, ipa: `/bu-gyn a-çëk më/`},{tr: `Yarın geliyorum.`, sq: `Vij nesër.`, ipa: `/ja-rën ge-li-jo-rum/`},{tr: `Akşam müsait misiniz?`, sq: `A jeni i lirë në mbrëmje?`, ipa: `/ak-sham my-sa-it mi-si-niz/`},{tr: `Beş dakika sonra.`, sq: `Pas pesë minutash.`, ipa: `/besh da-ki-ka son-ra/`}], grammar: `Në turqisht, “saat” përdoret edhe për “orë” edhe për “ora”. Për pyetje, “Saat kaç?” është forma më e thjeshtë. “Sonra” do të thotë “pas” dhe vendoset pas shprehjes së kohës.`, practice: [`Pyet “Sa është ora?” në turqisht.`,`Thuaj “Vij nesër.”`,`Krijo një fjali me “bugün”.`,`Thuaj “Pas pesë minutash.”`,`Pyet nëse një muze është i hapur sot.`]},{day: 7, title: `Në aeroport`, title_native: `Havaalanında`, focus: `Në Aeroportin e Stambollit ose Sabiha Gökçen, duhet të gjesh bagazhin, daljen dhe transportin. Sot mëson fjalë praktike për mbërritje.`, vocab: [{tr: `havaalanı`, sq: `aeroport`, ipa: `/ha-va-a-la-në/`},{tr: `pasaport`, sq: `pasaportë`, ipa: `/pa-sa-port/`},{tr: `bagaj`, sq: `bagazh`, ipa: `/ba-gazh/`},{tr: `çıkış`, sq: `dalje`, ipa: `/çë-kësh/`},{tr: `giriş`, sq: `hyrje`, ipa: `/gi-rish/`},{tr: `uçak`, sq: `avion`, ipa: `/u-çak/`},{tr: `bilet`, sq: `biletë`, ipa: `/bi-let/`},{tr: `kapı`, sq: `portë`, ipa: `/ka-pë/`},{tr: `gecikme`, sq: `vonesë`, ipa: `/ge-xhik-me/`},{tr: `gümrük`, sq: `doganë`, ipa: `/gym-ryk/`}], phrases: [{tr: `Pasaport kontrolü nerede?`, sq: `Ku është kontrolli i pasaportave?`, ipa: `/pa-sa-port kon-tro-ly ne-re-de/`},{tr: `Bagajım nerede?`, sq: `Ku është bagazhi im?`, ipa: `/ba-ga-zhëm ne-re-de/`},{tr: `Çıkış nerede?`, sq: `Ku është dalja?`, ipa: `/çë-kësh ne-re-de/`},{tr: `Uçağım gecikti.`, sq: `Avioni im u vonua.`, ipa: `/u-ça-ëm ge-xhik-ti/`},{tr: `Taksi nerede?`, sq: `Ku është taksia?`, ipa: `/tak-si ne-re-de/`},{tr: `Biletimi gösterebilir miyim?`, sq: `A mund ta tregoj biletën time?`, ipa: `/bi-le-ti-mi gœs-te-re-bi-lir mi-jim/`}], grammar: `Prapashtesa “-ım/-im/-um/-üm” tregon “im/e imja”, si “bagajım” = “bagazhi im”. Në udhëtim do ta dëgjosh shumë te “biletim”, “pasaportum” dhe “otelim”.`, practice: [`Pyet ku është dalja.`,`Thuaj “Bagazhi im” në turqisht.`,`Krijo një fjali me “uçağım”.`,`Pyet ku është taksia.`,`Thuaj se avioni yt është vonuar.`]},{day: 8, title: `Taksi dhe udhëtim me makinë`, title_native: `Taksi ve araba yolculuğu`, focus: `Kur merr taksi në Stamboll, Izmir ose Antalia, duhet të japësh destinacionin dhe të pyesësh për çmimin. Sot mëson fraza të qarta dhe të shkurtra.`, vocab: [{tr: `taksi`, sq: `taksi`, ipa: `/tak-si/`},{tr: `adres`, sq: `adresë`, ipa: `/ad-res/`},{tr: `otel`, sq: `hotel`, ipa: `/o-tel/`},{tr: `merkez`, sq: `qendër`, ipa: `/mer-kez/`},{tr: `sağ`, sq: `djathtas`, ipa: `/sa-a/`},{tr: `sol`, sq: `majtas`, ipa: `/sol/`},{tr: `düz`, sq: `drejt`, ipa: `/dyz/`},{tr: `yakın`, sq: `afër`, ipa: `/ja-kën/`},{tr: `uzak`, sq: `larg`, ipa: `/u-zak/`},{tr: `ücret`, sq: `tarifë`, ipa: `/yxh-ret/`}], phrases: [{tr: `Bu adrese gider misiniz?`, sq: `A shkoni në këtë adresë?`, ipa: `/bu ad-re-se gi-der mi-si-niz/`},{tr: `Otele gidiyorum.`, sq: `Po shkoj në hotel.`, ipa: `/o-te-le gi-di-jo-rum/`},{tr: `Ne kadar tutar?`, sq: `Sa kushton afërsisht?`, ipa: `/ne ka-dar tu-tar/`},{tr: `Sağa dönün lütfen.`, sq: `Kthehuni djathtas, ju lutem.`, ipa: `/sa-a dœ-nyn lyt-fen/`},{tr: `Solda durun lütfen.`, sq: `Ndaloni majtas, ju lutem.`, ipa: `/sol-da du-run lyt-fen/`},{tr: `Burada inebilir miyim?`, sq: `A mund të zbres këtu?`, ipa: `/bu-ra-da i-ne-bi-lir mi-jim/`}], grammar: `“Gidiyorum” do të thotë “po shkoj”. Për të kërkuar diçka me mirësjellje, përdor “lütfen” në fund. Në taksi, foljet urdhërore të sjellshme si “dönün” dhe “durun” janë shumë të dobishme.`, practice: [`Thuaj shoferit: “Po shkoj në hotel.”`,`Pyet “Sa kushton afërsisht?”`,`Jep udhëzimin “Kthehuni djathtas.”`,`Thuaj “Ndaloni majtas, ju lutem.”`,`Pyet nëse mund të zbresësh këtu.`]},{day: 9, title: `Hotele dhe regjistrim`, title_native: `Otel ve giriş işlemleri`, focus: `Në hotel në Kapadoki, Antalia ose Stamboll, duhet të japësh emrin dhe të pyesësh për dhomën. Sot mëson fjalorin kryesor të check-in.`, vocab: [{tr: `otel`, sq: `hotel`, ipa: `/o-tel/`},{tr: `rezervasyon`, sq: `rezervim`, ipa: `/re-zer-va-sjon/`},{tr: `oda`, sq: `dhomë`, ipa: `/o-da/`},{tr: `anahtar`, sq: `çelës`, ipa: `/a-nah-tar/`},{tr: `kimlik`, sq: `kartë identiteti`, ipa: `/kim-lik/`},{tr: `pasaport`, sq: `pasaportë`, ipa: `/pa-sa-port/`},{tr: `kahvaltı`, sq: `mëngjes`, ipa: `/kah-val-të/`},{tr: `asansör`, sq: `ashensor`, ipa: `/a-san-sœr/`},{tr: `kat`, sq: `kat`, ipa: `/kat/`},{tr: `gece`, sq: `natë`, ipa: `/ge-xhe/`}], phrases: [{tr: `Rezervasyonum var.`, sq: `Kam rezervim.`, ipa: `/re-zer-va-sjo-num var/`},{tr: `Benim adım Elira.`, sq: `Emri im është Elira.`, ipa: `/be-nim a-dëm e-li-ra/`},{tr: `Odam hazır mı?`, sq: `A është gati dhoma ime?`, ipa: `/o-dam ha-zër më/`},{tr: `Kahvaltı saat kaçta?`, sq: `Në ç’orë është mëngjesi?`, ipa: `/kah-val-të sa-at kaç-ta/`},{tr: `Wi-Fi şifresi nedir?`, sq: `Cili është fjalëkalimi i Wi-Fi?`, ipa: `/waj-faj shi-fre-si ne-dir/`},{tr: `Anahtar lütfen.`, sq: `Çelësin, ju lutem.`, ipa: `/a-nah-tar lyt-fen/`}], grammar: `“Rezervasyonum var” fjalë për fjalë do të thotë “rezervimi im ka/ekziston”, por në shqip e përkthejmë “kam rezervim”. “-um” tregon pronësi: rezervasyonum = rezervimi im.`, practice: [`Thuaj në recepsion: “Kam rezervim.”`,`Pyet nëse dhoma është gati.`,`Pyet për fjalëkalimin e Wi-Fi.`,`Thuaj “Çelësin, ju lutem.”`,`Pyet në ç’orë është mëngjesi.`]},{day: 10, title: `Rrugët dhe orientimi`, title_native: `Yollar ve yön bulma`, focus: `Në lagje si Kadıköy, Taksim ose Kaleiçi, orientimi është thelbësor. Sot mëson të pyesësh për drejtim dhe të kuptosh përgjigje të thjeshta.`, vocab: [{tr: `yol`, sq: `rrugë`, ipa: `/jol/`},{tr: `sokak`, sq: `rrugicë`, ipa: `/so-kak/`},{tr: `cadde`, sq: `bulevard`, ipa: `/xhad-de/`},{tr: `meydan`, sq: `shesh`, ipa: `/mej-dan/`},{tr: `köşe`, sq: `qoshe`, ipa: `/kœ-she/`},{tr: `karşı`, sq: `përballë`, ipa: `/kar-shë/`},{tr: `yanında`, sq: `pranë`, ipa: `/ja-nën-da/`},{tr: `önünde`, sq: `përpara`, ipa: `/œ-nyn-de/`},{tr: `arkasında`, sq: `prapa`, ipa: `/ar-ka-sën-da/`},{tr: `harita`, sq: `hartë`, ipa: `/ha-ri-ta/`}], phrases: [{tr: `Bu adres nerede?`, sq: `Ku është kjo adresë?`, ipa: `/bu ad-res ne-re-de/`},{tr: `Haritada gösterebilir misiniz?`, sq: `A mund ta tregoni në hartë?`, ipa: `/ha-ri-ta-da gœs-te-re-bi-lir mi-si-niz/`},{tr: `Düz gidin.`, sq: `Shkoni drejt.`, ipa: `/dyz gi-din/`},{tr: `Sağa dönün.`, sq: `Kthehuni djathtas.`, ipa: `/sa-a dœ-nyn/`},{tr: `Solda.`, sq: `Është majtas.`, ipa: `/sol-da/`},{tr: `Meydanın yanında.`, sq: `Pranë sheshit.`, ipa: `/mej-da-nën ja-nën-da/`}], grammar: `Prapashtesat e vendit janë shumë të rëndësishme: “-da/-de” do të thotë “në/te”. “Solda” = “majtas”, “haritada” = “në hartë”. Këto forma do t’i përdorësh vazhdimisht për orientim.`, practice: [`Pyet ku është një adresë.`,`Thuaj “Shkoni drejt” në turqisht.`,`Jep udhëzim me “sağa”.`,`Përkthe “Meydanın yanında.”`,`Krijo një pyetje me “harita”.`]},{day: 11, title: `Transporti publik`, title_native: `Toplu taşıma`, focus: `Në Stamboll, transporti publik përfshin metro, tramvaj, traget dhe autobus. Sot mëson si të blesh bileta dhe të gjesh linjën e duhur.`, vocab: [{tr: `metro`, sq: `metro`, ipa: `/met-ro/`},{tr: `tramvay`, sq: `tramvaj`, ipa: `/tram-vaj/`},{tr: `otobüs`, sq: `autobus`, ipa: `/o-to-bys/`},{tr: `vapur`, sq: `traget`, ipa: `/va-pur/`},{tr: `durak`, sq: `stacion`, ipa: `/du-rak/`},{tr: `istasyon`, sq: `stacion metroje`, ipa: `/is-tas-jon/`},{tr: `kart`, sq: `kartë`, ipa: `/kart/`},{tr: `bakiye`, sq: `bilanc`, ipa: `/ba-ki-je/`},{tr: `hat`, sq: `linjë`, ipa: `/hat/`},{tr: `aktarma`, sq: `ndërrim linje`, ipa: `/ak-tar-ma/`}], phrases: [{tr: `İstanbulkart nereden alabilirim?`, sq: `Ku mund të blej Istanbulkart?`, ipa: `/is-tan-bul-kart ne-re-den a-la-bi-li-rim/`},{tr: `Bu metro Taksim’e gider mi?`, sq: `A shkon kjo metro në Taksim?`, ipa: `/bu met-ro tak-sim-e gi-der mi/`},{tr: `Kaç durak var?`, sq: `Sa stacione ka?`, ipa: `/kaç du-rak var/`},{tr: `Aktarma yapmam gerekiyor.`, sq: `Më duhet të ndërroj linjë.`, ipa: `/ak-tar-ma jap-mam ge-re-ki-jor/`},{tr: `Bakiye yüklemek istiyorum.`, sq: `Dua të shtoj bilanc.`, ipa: `/ba-ki-je jyk-le-mek is-ti-jo-rum/`},{tr: `Son durak neresi?`, sq: `Cili është stacioni i fundit?`, ipa: `/son du-rak ne-re-si/`}], grammar: `“Gider mi?” do të thotë “a shkon?”. Për destinacione përdoret shpesh “-e/-a”, si “Taksim’e”. “İstiyorum” do të thotë “dua” dhe mund ta lidhësh me një veprim: “almak istiyorum” = dua të blej.`, practice: [`Pyet nëse metroja shkon në Taksim.`,`Thuaj “Dua të shtoj bilanc.”`,`Pyet sa stacione ka.`,`Krijo një fjali me “aktarma”.`,`Pyet ku mund të blesh Istanbulkart.`]},{day: 12, title: `Kafe dhe pije`, title_native: `Kafe ve içecekler`, focus: `Në një kafene në Karaköy ose Kadıköy, mund të porosisësh çaj turk, kafe turke ose ujë. Sot mëson të porosisësh me mirësjellje.`, vocab: [{tr: `çay`, sq: `çaj`, ipa: `/çaj/`},{tr: `kahve`, sq: `kafe`, ipa: `/kah-ve/`},{tr: `Türk kahvesi`, sq: `kafe turke`, ipa: `/tyrk kah-ve-si/`},{tr: `su`, sq: `ujë`, ipa: `/su/`},{tr: `süt`, sq: `qumësht`, ipa: `/syt/`},{tr: `şeker`, sq: `sheqer`, ipa: `/she-ker/`},{tr: `bardak`, sq: `gotë`, ipa: `/bar-dak/`},{tr: `fincan`, sq: `filxhan`, ipa: `/fin-xhan/`},{tr: `soğuk`, sq: `i ftohtë`, ipa: `/so-uk/`},{tr: `sıcak`, sq: `i ngrohtë`, ipa: `/së-xhak/`}], phrases: [{tr: `Bir çay lütfen.`, sq: `Një çaj, ju lutem.`, ipa: `/bir çaj lyt-fen/`},{tr: `Türk kahvesi istiyorum.`, sq: `Dua kafe turke.`, ipa: `/tyrk kah-ve-si is-ti-jo-rum/`},{tr: `Şekersiz olsun.`, sq: `Të jetë pa sheqer.`, ipa: `/she-ker-siz ol-sun/`},{tr: `Az şekerli olsun.`, sq: `Të jetë me pak sheqer.`, ipa: `/az she-ker-li ol-sun/`},{tr: `Bir bardak su alabilir miyim?`, sq: `A mund të marr një gotë ujë?`, ipa: `/bir bar-dak su a-la-bi-lir mi-jim/`},{tr: `Hesap lütfen.`, sq: `Llogarinë, ju lutem.`, ipa: `/he-sap lyt-fen/`}], grammar: `Në turqisht “-siz” do të thotë “pa”, si “şekersiz” = pa sheqer. “-li” tregon “me”, si “şekerli” = me sheqer. Kjo është shumë e dobishme për porosi ushqimi dhe pijesh.`, practice: [`Porosit një çaj në turqisht.`,`Thuaj “pa sheqer”.`,`Thuaj “me pak sheqer”.`,`Pyet për një gotë ujë.`,`Kërko llogarinë në fund të porosisë.`]},{day: 13, title: `Mëngjesi turk`, title_native: `Türk kahvaltısı`, focus: `Mëngjesi turk është pjesë e rëndësishme e kulturës. Sot mëson fjalë për ushqimet që mund të shohësh në një kahvaltı në Van, Stamboll ose Izmir.`, vocab: [{tr: `kahvaltı`, sq: `mëngjes`, ipa: `/kah-val-të/`},{tr: `ekmek`, sq: `bukë`, ipa: `/ek-mek/`},{tr: `peynir`, sq: `djathë`, ipa: `/pej-nir/`},{tr: `zeytin`, sq: `ullinj`, ipa: `/zej-tin/`},{tr: `yumurta`, sq: `vezë`, ipa: `/ju-mur-ta/`},{tr: `bal`, sq: `mjaltë`, ipa: `/bal/`},{tr: `reçel`, sq: `reçel`, ipa: `/re-çel/`},{tr: `domates`, sq: `domate`, ipa: `/do-ma-tes/`},{tr: `salatalık`, sq: `kastravec`, ipa: `/sa-la-ta-lëk/`},{tr: `menemen`, sq: `menemen`, ipa: `/me-ne-men/`}], phrases: [{tr: `Kahvaltı istiyorum.`, sq: `Dua mëngjes.`, ipa: `/kah-val-të is-ti-jo-rum/`},{tr: `Menemen var mı?`, sq: `A ka menemen?`, ipa: `/me-ne-men var më/`},{tr: `Peynir alabilir miyim?`, sq: `A mund të marr djathë?`, ipa: `/pej-nir a-la-bi-lir mi-jim/`},{tr: `Ekmek taze mi?`, sq: `A është buka e freskët?`, ipa: `/ek-mek ta-ze mi/`},{tr: `Yumurta nasıl?`, sq: `Si është veza?`, ipa: `/ju-mur-ta na-sël/`},{tr: `Çok lezzetli.`, sq: `Shumë e shijshme.`, ipa: `/çok lez-zet-li/`}], grammar: `“Var mı?” pyet nëse ka diçka në menu. Për komplimente, “çok lezzetli” është frazë e thjeshtë dhe shumë e mirëpritur. Në restorante familjare, një kompliment i vogël krijon menjëherë atmosferë më të ngrohtë.`, practice: [`Pyet nëse ka menemen.`,`Thuaj “Dua mëngjes.”`,`Kërko bukë.`,`Thuaj “Shumë e shijshme.”`,`Krijo një fjali me “peynir”.`]},{day: 14, title: `Në restorant`, title_native: `Restoranda`, focus: `Në restorant në Gaziantep, Bursa ose Stamboll, duhet të kërkosh menu, të porosisësh dhe të paguash. Sot mëson fraza të dobishme për një darkë të thjeshtë.`, vocab: [{tr: `restoran`, sq: `restorant`, ipa: `/res-to-ran/`},{tr: `menü`, sq: `menu`, ipa: `/me-ny/`},{tr: `yemek`, sq: `ushqim`, ipa: `/je-mek/`},{tr: `çorba`, sq: `supë`, ipa: `/çor-ba/`},{tr: `salata`, sq: `sallatë`, ipa: `/sa-la-ta/`},{tr: `tavuk`, sq: `pulë`, ipa: `/ta-vuk/`},{tr: `et`, sq: `mish`, ipa: `/et/`},{tr: `balık`, sq: `peshk`, ipa: `/ba-lëk/`},{tr: `pilav`, sq: `pilaf`, ipa: `/pi-lav/`},{tr: `hesap`, sq: `llogari`, ipa: `/he-sap/`}], phrases: [{tr: `Menü alabilir miyim?`, sq: `A mund të marr menunë?`, ipa: `/me-ny a-la-bi-lir mi-jim/`},{tr: `Ne önerirsiniz?`, sq: `Çfarë rekomandoni?`, ipa: `/ne œ-ne-rir-si-niz/`},{tr: `Tavuk istiyorum.`, sq: `Dua pulë.`, ipa: `/ta-vuk is-ti-jo-rum/`},{tr: `Vejetaryen yemek var mı?`, sq: `A ka ushqim vegjetarian?`, ipa: `/ve-je-tar-jen je-mek var më/`},{tr: `Hesap alabilir miyim?`, sq: `A mund të marr llogarinë?`, ipa: `/he-sap a-la-bi-lir mi-jim/`},{tr: `Kartla ödeyebilir miyim?`, sq: `A mund të paguaj me kartë?`, ipa: `/kart-la œ-de-je-bi-lir mi-jim/`}], grammar: `“Miyım/miyim” në fund të pyetjes e bën kërkesën të sjellshme: “alabilir miyim?” = a mund të marr? Kjo formë është më e mirë se një urdhër i drejtpërdrejtë kur flet me kamerierin.`, practice: [`Kërko menunë në turqisht.`,`Pyet çfarë rekomandon kamerieri.`,`Thuaj “Dua pulë.”`,`Pyet nëse ka ushqim vegjetarian.`,`Pyet nëse mund të paguash me kartë.`]},{day: 15, title: `Dieta, alergji dhe preferenca`, title_native: `Diyet, alerji ve tercihler`, focus: `Nëse ke alergji ose kufizime ushqimore, duhet ta thuash qartë. Sot mëson shprehje të sigurta për restorante dhe kafene në Turqi.`, vocab: [{tr: `alerji`, sq: `alergji`, ipa: `/a-ler-zhi/`},{tr: `fıstık`, sq: `kikirikë`, ipa: `/fës-tëk/`},{tr: `süt`, sq: `qumësht`, ipa: `/syt/`},{tr: `gluten`, sq: `gluten`, ipa: `/glu-ten/`},{tr: `et`, sq: `mish`, ipa: `/et/`},{tr: `vejetaryen`, sq: `vegjetarian`, ipa: `/ve-je-tar-jen/`},{tr: `acı`, sq: `pikant`, ipa: `/a-xhë/`},{tr: `tuz`, sq: `kripë`, ipa: `/tuz/`},{tr: `şeker`, sq: `sheqer`, ipa: `/she-ker/`},{tr: `sos`, sq: `salcë`, ipa: `/sos/`}], phrases: [{tr: `Fıstık alerjim var.`, sq: `Kam alergji nga kikirikët.`, ipa: `/fës-tëk a-ler-zhim var/`},{tr: `Et yemiyorum.`, sq: `Nuk ha mish.`, ipa: `/et je-mi-jo-rum/`},{tr: `Süt var mı?`, sq: `A ka qumësht?`, ipa: `/syt var më/`},{tr: `Acı olmasın lütfen.`, sq: `Të mos jetë pikant, ju lutem.`, ipa: `/a-xhë ol-ma-sën lyt-fen/`},{tr: `Glutensiz var mı?`, sq: `A ka pa gluten?`, ipa: `/glu-ten-siz var më/`},{tr: `Sosu ayrı alabilir miyim?`, sq: `A mund ta marr salcën veçmas?`, ipa: `/so-su aj-rë a-la-bi-lir mi-jim/`}], grammar: `“Yemiyorum” do të thotë “nuk ha”. Në turqisht mohimi shpesh futet brenda foljes me “-mı/-mi/-ma/-me”. “Olmasın” do të thotë “të mos jetë”, shumë e dobishme për “acı olmasın”.`, practice: [`Thuaj se nuk ha mish.`,`Thuaj se ke alergji nga kikirikët.`,`Pyet nëse ka qumësht.`,`Kërko që ushqimi të mos jetë pikant.`,`Pyet nëse ka opsion pa gluten.`]},{day: 16, title: `Blerje në dyqan`, title_native: `Mağazada alışveriş`, focus: `Në dyqane në Izmir ose Stamboll, duhet të pyesësh për çmimin, madhësinë dhe pagesën. Sot mëson fraza të drejtpërdrejta për pazar.`, vocab: [{tr: `mağaza`, sq: `dyqan`, ipa: `/ma-a-za/`},{tr: `alışveriş`, sq: `blerje`, ipa: `/a-lësh-ve-rish/`},{tr: `fiyat`, sq: `çmim`, ipa: `/fi-jat/`},{tr: `beden`, sq: `masë`, ipa: `/be-den/`},{tr: `renk`, sq: `ngjyrë`, ipa: `/renk/`},{tr: `küçük`, sq: `i vogël`, ipa: `/ky-çyk/`},{tr: `büyük`, sq: `i madh`, ipa: `/by-jyk/`},{tr: `nakit`, sq: `para në dorë`, ipa: `/na-kit/`},{tr: `kart`, sq: `kartë`, ipa: `/kart/`},{tr: `fiş`, sq: `kupon`, ipa: `/fish/`}], phrases: [{tr: `Bu kaç para?`, sq: `Sa kushton kjo?`, ipa: `/bu kaç pa-ra/`},{tr: `Başka beden var mı?`, sq: `A ka masë tjetër?`, ipa: `/bash-ka be-den var më/`},{tr: `Mavi renk var mı?`, sq: `A ka ngjyrë blu?`, ipa: `/ma-vi renk var më/`},{tr: `Deneyebilir miyim?`, sq: `A mund ta provoj?`, ipa: `/de-ne-je-bi-lir mi-jim/`},{tr: `Kart geçiyor mu?`, sq: `A pranohet karta?`, ipa: `/kart ge-çi-jor mu/`},{tr: `Fiş alabilir miyim?`, sq: `A mund të marr kuponin?`, ipa: `/fish a-la-bi-lir mi-jim/`}], grammar: `“Başka” do të thotë “tjetër”. Mund ta përdorësh me shumë fjalë: “başka renk”, “başka beden”, “başka seçenek”. Në dyqane është një fjalë shumë fleksibile.`, practice: [`Pyet sa kushton një bluzë.`,`Pyet për masë tjetër.`,`Pyet nëse pranohet karta.`,`Thuaj “A mund ta provoj?”`,`Kërko kuponin.`]},{day: 17, title: `Në treg dhe pazar`, title_native: `Pazarda`, focus: `Pazaret turke janë plot fruta, erëza dhe zëra tregtarësh. Sot mëson si të blesh thjesht në një treg në Kadıköy, Bursa ose Antalia.`, vocab: [{tr: `pazar`, sq: `treg`, ipa: `/pa-zar/`},{tr: `meyve`, sq: `fruta`, ipa: `/mej-ve/`},{tr: `sebze`, sq: `perime`, ipa: `/seb-ze/`},{tr: `elma`, sq: `mollë`, ipa: `/el-ma/`},{tr: `portakal`, sq: `portokall`, ipa: `/por-ta-kal/`},{tr: `domates`, sq: `domate`, ipa: `/do-ma-tes/`},{tr: `kilo`, sq: `kilogram`, ipa: `/ki-lo/`},{tr: `yarım`, sq: `gjysmë`, ipa: `/ja-rëm/`},{tr: `taze`, sq: `i freskët`, ipa: `/ta-ze/`},{tr: `poşet`, sq: `qese`, ipa: `/po-shet/`}], phrases: [{tr: `Bir kilo elma lütfen.`, sq: `Një kilogram mollë, ju lutem.`, ipa: `/bir ki-lo el-ma lyt-fen/`},{tr: `Yarım kilo domates istiyorum.`, sq: `Dua gjysmë kilogram domate.`, ipa: `/ja-rëm ki-lo do-ma-tes is-ti-jo-rum/`},{tr: `Taze mi?`, sq: `A është e freskët?`, ipa: `/ta-ze mi/`},{tr: `Poşet alabilir miyim?`, sq: `A mund të marr një qese?`, ipa: `/po-shet a-la-bi-lir mi-jim/`},{tr: `Toplam ne kadar?`, sq: `Sa është gjithsej?`, ipa: `/top-lam ne ka-dar/`},{tr: `Biraz daha verir misiniz?`, sq: `A mund të më jepni pak më shumë?`, ipa: `/bi-raz da-ha ve-rir mi-si-niz/`}], grammar: `“Ne kadar?” do të thotë “sa?” për sasi ose çmim. “Toplam ne kadar?” është shumë e dobishme kur blen disa gjëra. “Biraz daha” do të thotë “pak më shumë”.`, practice: [`Kërko një kilogram mollë.`,`Kërko gjysmë kilogram domate.`,`Pyet nëse produkti është i freskët.`,`Pyet sa është gjithsej.`,`Kërko një qese.`]},{day: 18, title: `Rroba dhe ngjyra`, title_native: `Kıyafetler ve renkler`, focus: `Kur blen rroba ose kërkon diçka në valixhe, ngjyrat dhe emrat e rrobave janë të rëndësishme. Sot mëson fjalë praktike për dyqane.`, vocab: [{tr: `gömlek`, sq: `këmishë`, ipa: `/gœm-lek/`},{tr: `pantolon`, sq: `pantallona`, ipa: `/pan-to-lon/`},{tr: `elbise`, sq: `fustan`, ipa: `/el-bi-se/`},{tr: `ayakkabı`, sq: `këpucë`, ipa: `/a-jak-ka-bë/`},{tr: `çanta`, sq: `çantë`, ipa: `/çan-ta/`},{tr: `beyaz`, sq: `i bardhë`, ipa: `/be-jaz/`},{tr: `siyah`, sq: `i zi`, ipa: `/si-jah/`},{tr: `kırmızı`, sq: `i kuq`, ipa: `/kër-më-zë/`},{tr: `mavi`, sq: `blu`, ipa: `/ma-vi/`},{tr: `yeşil`, sq: `jeshil`, ipa: `/je-shil/`}], phrases: [{tr: `Siyah gömlek var mı?`, sq: `A ka këmishë të zezë?`, ipa: `/si-jah gœm-lek var më/`},{tr: `Bu beden küçük.`, sq: `Kjo masë është e vogël.`, ipa: `/bu be-den ky-çyk/`},{tr: `Daha büyük var mı?`, sq: `A ka më të madhe?`, ipa: `/da-ha by-jyk var më/`},{tr: `Ayakkabı denemek istiyorum.`, sq: `Dua të provoj këpucë.`, ipa: `/a-jak-ka-bë de-ne-mek is-ti-jo-rum/`},{tr: `Bu rengi beğendim.`, sq: `Më pëlqeu kjo ngjyrë.`, ipa: `/bu ren-gi be-en-dim/`},{tr: `Alıyorum.`, sq: `Po e marr.`, ipa: `/a-lë-jo-rum/`}], grammar: `“Daha” do të thotë “më” për krahasim: “daha büyük” = më i madh, “daha küçük” = më i vogël. Është mënyrë shumë e lehtë për të kërkuar madhësi ose çmime më të përshtatshme.`, practice: [`Pyet për një këmishë të zezë.`,`Thuaj se masa është e vogël.`,`Kërko diçka më të madhe.`,`Thuaj se të pëlqen kjo ngjyrë.`,`Krijo një fjali me “ayakkabı”.`]},{day: 19, title: `Shëndeti dhe farmacia`, title_native: `Sağlık ve eczane`, focus: `Nëse nuk ndihesh mirë gjatë udhëtimit, farmacia është ndalesa e parë. Sot mëson fjalë për simptoma të zakonshme dhe kërkesa bazë.`, vocab: [{tr: `eczane`, sq: `farmaci`, ipa: `/exh-za-ne/`},{tr: `ilaç`, sq: `ilaç, medikament`, ipa: `/i-laç/`},{tr: `ağrı`, sq: `dhimbje`, ipa: `/a-rë/`},{tr: `baş`, sq: `kokë`, ipa: `/bash/`},{tr: `mide`, sq: `stomak`, ipa: `/mi-de/`},{tr: `ateş`, sq: `temperaturë`, ipa: `/a-tesh/`},{tr: `öksürük`, sq: `kollë`, ipa: `/œk-sy-ryk/`},{tr: `hasta`, sq: `i sëmurë`, ipa: `/has-ta/`},{tr: `doktor`, sq: `doktor`, ipa: `/dok-tor/`},{tr: `reçete`, sq: `recetë`, ipa: `/re-çe-te/`}], phrases: [{tr: `Eczane nerede?`, sq: `Ku është farmacia?`, ipa: `/exh-za-ne ne-re-de/`},{tr: `Başım ağrıyor.`, sq: `Më dhemb koka.`, ipa: `/ba-shëm a-rë-jor/`},{tr: `Mideme iyi gelmeyen bir şey yedim.`, sq: `Kam ngrënë diçka që nuk më bëri mirë për stomakun.`, ipa: `/mi-de-me i-ji gel-me-jen bir shej je-dim/`},{tr: `Ateşim var.`, sq: `Kam temperaturë.`, ipa: `/a-te-shim var/`},{tr: `Reçetesiz ilaç var mı?`, sq: `A ka ilaç pa recetë?`, ipa: `/re-çe-te-siz i-laç var më/`},{tr: `Doktora gitmem gerekiyor.`, sq: `Më duhet të shkoj te doktori.`, ipa: `/dok-to-ra git-mem ge-re-ki-jor/`}], grammar: `Për dhimbje përdoret shpesh struktura “... ağrıyor”. “Başım ağrıyor” = më dhemb koka, “midem ağrıyor” = më dhemb stomaku. Prapashtesa e pronësisë tregon pjesën e trupit tënd.`, practice: [`Pyet ku është farmacia.`,`Thuaj “Më dhemb koka.”`,`Thuaj “Kam temperaturë.”`,`Pyet nëse ka ilaç pa recetë.`,`Thuaj se duhet të shkosh te doktori.`]},{day: 20, title: `Emergjenca dhe ndihma`, title_native: `Acil durum ve yardım`, focus: `Edhe nëse shpreson të mos i përdorësh, frazat e emergjencës janë të rëndësishme. Sot mëson si të kërkosh ndihmë në rrugë, hotel ose stacion.`, vocab: [{tr: `yardım`, sq: `ndihmë`, ipa: `/jar-dëm/`},{tr: `acil`, sq: `urgjent`, ipa: `/a-xhil/`},{tr: `polis`, sq: `polici`, ipa: `/po-lis/`},{tr: `ambulans`, sq: `ambulancë`, ipa: `/am-bu-lans/`},{tr: `hastane`, sq: `spital`, ipa: `/has-ta-ne/`},{tr: `kaybolmak`, sq: `humb`, ipa: `/kaj-bol-mak/`},{tr: `tehlike`, sq: `rrezik`, ipa: `/teh-li-ke/`},{tr: `telefon`, sq: `telefon`, ipa: `/te-le-fon/`},{tr: `adres`, sq: `adresë`, ipa: `/ad-res/`},{tr: `lütfen`, sq: `ju lutem`, ipa: `/lyt-fen/`}], phrases: [{tr: `Yardım edin lütfen.`, sq: `Më ndihmoni, ju lutem.`, ipa: `/jar-dëm e-din lyt-fen/`},{tr: `Acil durum var.`, sq: `Ka një emergjencë.`, ipa: `/a-xhil du-rum var/`},{tr: `Polisi arayın.`, sq: `Thirrni policinë.`, ipa: `/po-li-si a-ra-jën/`},{tr: `Ambulans çağırın.`, sq: `Thirrni ambulancën.`, ipa: `/am-bu-lans ça-ër-ën/`},{tr: `Kayboldum.`, sq: `Kam humbur.`, ipa: `/kaj-bol-dum/`},{tr: `Telefonumu kaybettim.`, sq: `Kam humbur telefonin.`, ipa: `/te-le-fo-nu-mu kaj-bet-tim/`}], grammar: `Urdhërorja e sjellshme për grup ose person formal shpesh mbaron me “-ın/-in/-un/-ün”: “arayın”, “çağırın”, “edin”. Në emergjencë, fjalitë e shkurtra janë më të mira se shpjegimet e gjata.`, practice: [`Thuaj “Më ndihmoni, ju lutem.”`,`Thuaj “Kam humbur.”`,`Kërko që dikush të thërrasë ambulancën.`,`Thuaj se ke humbur telefonin.`,`Krijo një frazë emergjence me “polis”.`]},{day: 21, title: `Marrja me qira dhe shërbime`, title_native: `Kiralama ve hizmetler`, focus: `Në udhëtim mund të marrësh me qira makinë, biçikletë ose të kërkosh lavanderi. Sot mëson fjalë praktike për shërbime të përditshme.`, vocab: [{tr: `kiralamak`, sq: `marr me qira`, ipa: `/ki-ra-la-mak/`},{tr: `araba`, sq: `makinë`, ipa: `/a-ra-ba/`},{tr: `bisiklet`, sq: `biçikletë`, ipa: `/bi-sik-let/`},{tr: `çamaşır`, sq: `rroba për larje`, ipa: `/ça-ma-shër/`},{tr: `temizleme`, sq: `pastrim`, ipa: `/te-miz-le-me/`},{tr: `tamir`, sq: `riparim`, ipa: `/ta-mir/`},{tr: `anahtar`, sq: `çelës`, ipa: `/a-nah-tar/`},{tr: `günlük`, sq: `ditor`, ipa: `/gyn-lyk/`},{tr: `saatlik`, sq: `për orë`, ipa: `/sa-at-lik/`},{tr: `ücret`, sq: `tarifë`, ipa: `/yxh-ret/`}], phrases: [{tr: `Araba kiralamak istiyorum.`, sq: `Dua të marr makinë me qira.`, ipa: `/a-ra-ba ki-ra-la-mak is-ti-jo-rum/`},{tr: `Günlük ücret ne kadar?`, sq: `Sa është tarifa ditore?`, ipa: `/gyn-lyk yxh-ret ne ka-dar/`},{tr: `Bisiklet var mı?`, sq: `A ka biçikletë?`, ipa: `/bi-sik-let var më/`},{tr: `Çamaşır yıkatmak istiyorum.`, sq: `Dua të laj rrobat.`, ipa: `/ça-ma-shër jë-kat-mak is-ti-jo-rum/`},{tr: `Ne zaman hazır olur?`, sq: `Kur do të jetë gati?`, ipa: `/ne za-man ha-zër o-lur/`},{tr: `Kimlik gerekiyor mu?`, sq: `A duhet kartë identiteti?`, ipa: `/kim-lik ge-re-ki-jor mu/`}], grammar: `“İstiyorum” kombinohet me folje në formën “-mak/-mek”: “kiralamak istiyorum” = dua të marr me qira. Kjo strukturë është shumë e dobishme sepse mund të shtosh shumë veprime të reja.`, practice: [`Thuaj se do të marrësh makinë me qira.`,`Pyet për tarifën ditore.`,`Pyet nëse ka biçikletë.`,`Pyet kur do të jetë gati.`,`Pyet nëse duhet kartë identiteti.`]},{day: 22, title: `Plazhi, moti dhe pushimet`, title_native: `Plaj, hava durumu ve tatil`, focus: `Në Antalia, Bodrum ose Çeşme, do të flasësh për plazh, diell dhe mot. Sot mëson fjalë për pushime dhe aktivitete jashtë.`, vocab: [{tr: `plaj`, sq: `plazh`, ipa: `/plazh/`},{tr: `deniz`, sq: `det`, ipa: `/de-niz/`},{tr: `güneş`, sq: `diell`, ipa: `/gy-nesh/`},{tr: `hava`, sq: `mot`, ipa: `/ha-va/`},{tr: `sıcak`, sq: `nxehtë`, ipa: `/së-xhak/`},{tr: `soğuk`, sq: `ftohtë`, ipa: `/so-uk/`},{tr: `rüzgar`, sq: `erë`, ipa: `/ryz-gar/`},{tr: `yağmur`, sq: `shi`, ipa: `/ja-mur/`},{tr: `şemsiye`, sq: `çadër`, ipa: `/shem-si-je/`},{tr: `havlu`, sq: `peshqir`, ipa: `/hav-lu/`}], phrases: [{tr: `Hava nasıl?`, sq: `Si është moti?`, ipa: `/ha-va na-sël/`},{tr: `Bugün çok sıcak.`, sq: `Sot është shumë nxehtë.`, ipa: `/bu-gyn çok së-xhak/`},{tr: `Plaj nerede?`, sq: `Ku është plazhi?`, ipa: `/plazh ne-re-de/`},{tr: `Denize girmek istiyorum.`, sq: `Dua të hyj në det.`, ipa: `/de-ni-ze gir-mek is-ti-jo-rum/`},{tr: `Şemsiye kiralayabilir miyim?`, sq: `A mund të marr çadër me qira?`, ipa: `/shem-si-je ki-ra-la-ja-bi-lir mi-jim/`},{tr: `Havlu var mı?`, sq: `A ka peshqir?`, ipa: `/hav-lu var më/`}], grammar: `“Hava nasıl?” është pyetja më e thjeshtë për motin. “Çok” vendoset para mbiemrit për “shumë”: “çok sıcak”, “çok güzel”, “çok soğuk”. Në biseda të përditshme, turqit e përdorin shumë shpesh.`, practice: [`Pyet si është moti.`,`Thuaj “Sot është shumë nxehtë.”`,`Pyet ku është plazhi.`,`Thuaj se do të hysh në det.`,`Kërko çadër me qira.`]},{day: 23, title: `Vizita në muze dhe atraksione`, title_native: `Müze ve gezilecek yerler`, focus: `Në Turqi ka muze, xhami, kështjella dhe vende historike. Sot mëson si të pyesësh për bileta, orare dhe rregulla në atraksione.`, vocab: [{tr: `müze`, sq: `muze`, ipa: `/my-ze/`},{tr: `bilet`, sq: `biletë`, ipa: `/bi-let/`},{tr: `giriş`, sq: `hyrje`, ipa: `/gi-rish/`},{tr: `çıkış`, sq: `dalje`, ipa: `/çë-kësh/`},{tr: `saat`, sq: `orar`, ipa: `/sa-at/`},{tr: `açık`, sq: `hapur`, ipa: `/a-çëk/`},{tr: `kapalı`, sq: `mbyllur`, ipa: `/ka-pa-lë/`},{tr: `fotoğraf`, sq: `fotografi`, ipa: `/fo-to-raf/`},{tr: `rehber`, sq: `guidë`, ipa: `/reh-ber/`},{tr: `tarih`, sq: `histori`, ipa: `/ta-rih/`}], phrases: [{tr: `Müze açık mı?`, sq: `A është muzeu hapur?`, ipa: `/my-ze a-çëk më/`},{tr: `Giriş ücreti ne kadar?`, sq: `Sa kushton hyrja?`, ipa: `/gi-rish yxh-re-ti ne ka-dar/`},{tr: `İki bilet lütfen.`, sq: `Dy bileta, ju lutem.`, ipa: `/i-ki bi-let lyt-fen/`},{tr: `Fotoğraf çekebilir miyim?`, sq: `A mund të bëj foto?`, ipa: `/fo-to-raf çe-ke-bi-lir mi-jim/`},{tr: `Rehber var mı?`, sq: `A ka guidë?`, ipa: `/reh-ber var më/`},{tr: `Saat kaçta kapanıyor?`, sq: `Në ç’orë mbyllet?`, ipa: `/sa-at kaç-ta ka-pa-në-jor/`}], grammar: `“Açık” do të thotë “hapur” dhe “kapalı” do të thotë “mbyllur”. Pyetja “... açık mı?” funksionon për muze, restorante, dyqane dhe zyra. Është një model shumë i dobishëm.`, practice: [`Pyet nëse muzeu është hapur.`,`Kërko dy bileta.`,`Pyet sa kushton hyrja.`,`Pyet nëse mund të bësh foto.`,`Pyet në ç’orë mbyllet muzeu.`]},{day: 24, title: `Telefoni, interneti dhe teknologjia`, title_native: `Telefon, internet ve teknoloji`, focus: `Për harta, bileta dhe përkthim, interneti është i domosdoshëm. Sot mëson si të kërkosh Wi-Fi, karikues ose kartë SIM.`, vocab: [{tr: `telefon`, sq: `telefon`, ipa: `/te-le-fon/`},{tr: `internet`, sq: `internet`, ipa: `/in-ter-net/`},{tr: `Wi-Fi`, sq: `Wi-Fi`, ipa: `/waj-faj/`},{tr: `şifre`, sq: `fjalëkalim`, ipa: `/shif-re/`},{tr: `şarj`, sq: `karikim`, ipa: `/sharzh/`},{tr: `priz`, sq: `prizë`, ipa: `/priz/`},{tr: `SIM kart`, sq: `kartë SIM`, ipa: `/sim kart/`},{tr: `paket`, sq: `paketë`, ipa: `/pa-ket/`},{tr: `mesaj`, sq: `mesazh`, ipa: `/me-sazh/`},{tr: `arama`, sq: `telefonatë`, ipa: `/a-ra-ma/`}], phrases: [{tr: `Wi-Fi şifresi nedir?`, sq: `Cili është fjalëkalimi i Wi-Fi?`, ipa: `/waj-faj shif-re-si ne-dir/`},{tr: `Telefonumu şarj edebilir miyim?`, sq: `A mund ta karikoj telefonin?`, ipa: `/te-le-fo-nu-mu sharzh e-de-bi-lir mi-jim/`},{tr: `Priz nerede?`, sq: `Ku është priza?`, ipa: `/priz ne-re-de/`},{tr: `SIM kart almak istiyorum.`, sq: `Dua të blej kartë SIM.`, ipa: `/sim kart al-mak is-ti-jo-rum/`},{tr: `İnternet paketi var mı?`, sq: `A ka paketë interneti?`, ipa: `/in-ter-net pa-ke-ti var më/`},{tr: `Mesaj geldi.`, sq: `Erdhi mesazh.`, ipa: `/me-sazh gel-di/`}], grammar: `“Edebilir miyim?” është formë e sjellshme për “a mund të bëj?”. E dëgjon te shumë folje të huazuara: “şarj edebilir miyim?” = a mund ta karikoj? Kjo është praktike në kafene, aeroport dhe hotel.`, practice: [`Pyet për fjalëkalimin e Wi-Fi.`,`Pyet ku është priza.`,`Thuaj se do të blesh kartë SIM.`,`Pyet nëse ka paketë interneti.`,`Kërko leje për të karikuar telefonin.`]},{day: 25, title: `Miqësi dhe biseda të vogla`, title_native: `Arkadaşlık ve küçük sohbetler`, focus: `Në Turqi, bisedat e vogla janë pjesë e mirësjelljes. Sot mëson pyetje të thjeshta për të folur me vendas në kafene, traget ose park.`, vocab: [{tr: `arkadaş`, sq: `mik`, ipa: `/ar-ka-dash/`},{tr: `sohbet`, sq: `bisedë`, ipa: `/soh-bet/`},{tr: `güzel`, sq: `i bukur`, ipa: `/gy-zel/`},{tr: `şehir`, sq: `qytet`, ipa: `/she-hir/`},{tr: `nereli`, sq: `nga ku`, ipa: `/ne-re-li/`},{tr: `iş`, sq: `punë`, ipa: `/ish/`},{tr: `tatil`, sq: `pushim`, ipa: `/ta-til/`},{tr: `aile`, sq: `familje`, ipa: `/a-i-le/`},{tr: `müzik`, sq: `muzikë`, ipa: `/my-zik/`},{tr: `film`, sq: `film`, ipa: `/film/`}], phrases: [{tr: `Nerelisiniz?`, sq: `Nga jeni?`, ipa: `/ne-re-li-si-niz/`},{tr: `Ben Arnavutluk’tanım.`, sq: `Jam nga Shqipëria.`, ipa: `/ben ar-na-vut-luk-ta-nëm/`},{tr: `Şehir çok güzel.`, sq: `Qyteti është shumë i bukur.`, ipa: `/she-hir çok gy-zel/`},{tr: `Burayı seviyorum.`, sq: `Më pëlqen ky vend.`, ipa: `/bu-ra-jë se-vi-jo-rum/`},{tr: `Ne iş yapıyorsunuz?`, sq: `Çfarë pune bëni?`, ipa: `/ne ish ja-pë-jor-su-nuz/`},{tr: `Sizinle tanışmak güzeldi.`, sq: `Ishte bukur t’ju takoja.`, ipa: `/si-zin-le ta-nësh-mak gy-zel-di/`}], grammar: `Forma “-siniz/-sunuz” është më formale ose më e sjellshme se forma e thjeshtë. “Nerelisiniz?” është më e përshtatshme me njerëz që sapo i takon. Me miq mund të dëgjosh “Nerelisin?”.`, practice: [`Pyet dikë nga është në formë të sjellshme.`,`Thuaj se je nga Shqipëria.`,`Bëj një kompliment për qytetin.`,`Thuaj se të pëlqen ky vend.`,`Mbylle bisedën me “Ishte bukur t’ju takoja.”`]},{day: 26, title: `Ftesa dhe plane`, title_native: `Davetler ve planlar`, focus: `Nëse takon njerëz gjatë udhëtimit, mund të bësh plane për kafe, darkë ose shëtitje. Sot mëson të ftosh dhe të përgjigjesh thjesht.`, vocab: [{tr: `davet`, sq: `ftesë`, ipa: `/da-vet/`},{tr: `plan`, sq: `plan`, ipa: `/plan/`},{tr: `bugün`, sq: `sot`, ipa: `/bu-gyn/`},{tr: `yarın`, sq: `nesër`, ipa: `/ja-rën/`},{tr: `müsait`, sq: `i lirë`, ipa: `/my-sa-it/`},{tr: `kahve`, sq: `kafe`, ipa: `/kah-ve/`},{tr: `yemek`, sq: `ushqim, darkë`, ipa: `/je-mek/`},{tr: `gezmek`, sq: `shëtis`, ipa: `/gez-mek/`},{tr: `buluşmak`, sq: `takohem`, ipa: `/bu-lush-mak/`},{tr: `sonra`, sq: `më vonë`, ipa: `/son-ra/`}], phrases: [{tr: `Bugün müsait misiniz?`, sq: `A jeni i lirë sot?`, ipa: `/bu-gyn my-sa-it mi-si-niz/`},{tr: `Kahve içmek ister misiniz?`, sq: `A dëshironi të pimë kafe?`, ipa: `/kah-ve iç-mek is-ter mi-si-niz/`},{tr: `Yarın buluşalım mı?`, sq: `A të takohemi nesër?`, ipa: `/ja-rën bu-lu-sha-lëm më/`},{tr: `Saat kaçta?`, sq: `Në ç’orë?`, ipa: `/sa-at kaç-ta/`},{tr: `Maalesef müsait değilim.`, sq: `Fatkeqësisht nuk jam i lirë.`, ipa: `/ma-a-le-sef my-sa-it de-i-lim/`},{tr: `Evet, memnuniyetle.`, sq: `Po, me kënaqësi.`, ipa: `/e-vet mem-nu-ni-jet-le/`}], grammar: `“İster misiniz?” është mënyrë e sjellshme për të pyetur “a dëshironi?”. “Buluşalım mı?” është një formë e natyrshme për “a të takohemi?”. Këto forma janë të mira për plane miqësore pa tingëlluar shumë të drejtpërdrejta.`, practice: [`Pyet dikë nëse është i lirë sot.`,`Fto dikë për kafe.`,`Sugjero takim nesër.`,`Refuzo me mirësjellje.`,`Prano me “Evet, memnuniyetle.”`]},{day: 27, title: `Problemet në hotel dhe qytet`, title_native: `Otelde ve şehirde sorunlar`, focus: `Në udhëtim mund të ketë zhurmë, problem me dhomën ose humbje objektesh. Sot mëson të shpjegosh probleme pa panik.`, vocab: [{tr: `sorun`, sq: `problem`, ipa: `/so-run/`},{tr: `bozuk`, sq: `i prishur`, ipa: `/bo-zuk/`},{tr: `gürültü`, sq: `zhurmë`, ipa: `/gy-ryl-ty/`},{tr: `temiz`, sq: `i pastër`, ipa: `/te-miz/`},{tr: `kirli`, sq: `i pisët`, ipa: `/kir-li/`},{tr: `su`, sq: `ujë`, ipa: `/su/`},{tr: `klima`, sq: `kondicioner`, ipa: `/kli-ma/`},{tr: `ışık`, sq: `dritë`, ipa: `/ë-shëk/`},{tr: `kayıp`, sq: `i humbur`, ipa: `/ka-jëp/`},{tr: `yardım`, sq: `ndihmë`, ipa: `/jar-dëm/`}], phrases: [{tr: `Bir sorun var.`, sq: `Ka një problem.`, ipa: `/bir so-run var/`},{tr: `Klima çalışmıyor.`, sq: `Kondicioneri nuk punon.`, ipa: `/kli-ma ça-lësh-më-jor/`},{tr: `Oda temiz değil.`, sq: `Dhoma nuk është e pastër.`, ipa: `/o-da te-miz de-il/`},{tr: `Çok gürültü var.`, sq: `Ka shumë zhurmë.`, ipa: `/çok gy-ryl-ty var/`},{tr: `Anahtarımı kaybettim.`, sq: `Kam humbur çelësin tim.`, ipa: `/a-nah-ta-rë-më kaj-bet-tim/`},{tr: `Yardımcı olabilir misiniz?`, sq: `A mund të më ndihmoni?`, ipa: `/jar-dëm-xhë o-la-bi-lir mi-si-niz/`}], grammar: `“Çalışmıyor” do të thotë “nuk punon”. Mund ta përdorësh për pajisje: “telefon çalışmıyor”, “klima çalışmıyor”, “Wi-Fi çalışmıyor”. Kjo është një nga foljet më praktike për probleme teknike.`, practice: [`Thuaj se ka një problem.`,`Thuaj se kondicioneri nuk punon.`,`Thuaj se dhoma nuk është e pastër.`,`Thuaj se ke humbur çelësin.`,`Kërko ndihmë me mirësjellje.`]},{day: 28, title: `Banka, para dhe pagesa`, title_native: `Banka, para ve ödeme`, focus: `Për ATM, pagesa me kartë dhe këmbim valutor, duhet fjalor i qartë. Sot mëson fraza praktike për para në Turqi.`, vocab: [{tr: `banka`, sq: `bankë`, ipa: `/ban-ka/`},{tr: `ATM`, sq: `bankomat`, ipa: `/a-te-me/`},{tr: `para`, sq: `para`, ipa: `/pa-ra/`},{tr: `nakit`, sq: `para në dorë`, ipa: `/na-kit/`},{tr: `kart`, sq: `kartë`, ipa: `/kart/`},{tr: `kredi kartı`, sq: `kartë krediti`, ipa: `/kre-di kar-të/`},{tr: `ödeme`, sq: `pagesë`, ipa: `/œ-de-me/`},{tr: `bozuk para`, sq: `monedha`, ipa: `/bo-zuk pa-ra/`},{tr: `fatura`, sq: `faturë`, ipa: `/fa-tu-ra/`},{tr: `kur`, sq: `kurs këmbimi`, ipa: `/kur/`}], phrases: [{tr: `ATM nerede?`, sq: `Ku është bankomati?`, ipa: `/a-te-me ne-re-de/`},{tr: `Nakit çekmek istiyorum.`, sq: `Dua të tërheq para.`, ipa: `/na-kit çek-mek is-ti-jo-rum/`},{tr: `Kartla ödeyebilir miyim?`, sq: `A mund të paguaj me kartë?`, ipa: `/kart-la œ-de-je-bi-lir mi-jim/`},{tr: `Nakit var.`, sq: `Kam para në dorë.`, ipa: `/na-kit var/`},{tr: `Bozuk para var mı?`, sq: `A keni monedha?`, ipa: `/bo-zuk pa-ra var më/`},{tr: `Fatura alabilir miyim?`, sq: `A mund të marr faturë?`, ipa: `/fa-tu-ra a-la-bi-lir mi-jim/`}], grammar: `“Kartla” do të thotë “me kartë”; prapashtesa “-la/-le” shpesh do të thotë “me”. Shembuj të tjerë: “nakitle” = me para në dorë, “telefonla” = me telefon.`, practice: [`Pyet ku është bankomati.`,`Thuaj se do të tërheqësh para.`,`Pyet nëse mund të paguash me kartë.`,`Kërko faturë.`,`Pyet nëse kanë monedha.`]},{day: 29, title: `Folje të përditshme për udhëtarë`, title_native: `Gezginler için günlük fiiller`, focus: `Sot përmbledh folje që përdoren çdo ditë: shkoj, marr, dua, blej dhe pres. Këto folje të ndihmojnë të krijosh fjali të reja në çdo qytet turk.`, vocab: [{tr: `gitmek`, sq: `shkoj`, ipa: `/git-mek/`},{tr: `gelmek`, sq: `vij`, ipa: `/gel-mek/`},{tr: `almak`, sq: `marr, blej`, ipa: `/al-mak/`},{tr: `vermek`, sq: `jap`, ipa: `/ver-mek/`},{tr: `istemek`, sq: `dua`, ipa: `/is-te-mek/`},{tr: `beklemek`, sq: `pres`, ipa: `/bek-le-mek/`},{tr: `bulmak`, sq: `gjej`, ipa: `/bul-mak/`},{tr: `sormak`, sq: `pyes`, ipa: `/sor-mak/`},{tr: `anlamak`, sq: `kuptoj`, ipa: `/an-la-mak/`},{tr: `konuşmak`, sq: `flas`, ipa: `/ko-nush-mak/`}], phrases: [{tr: `Otele gitmek istiyorum.`, sq: `Dua të shkoj në hotel.`, ipa: `/o-te-le git-mek is-ti-jo-rum/`},{tr: `Bir bilet almak istiyorum.`, sq: `Dua të blej një biletë.`, ipa: `/bir bi-let al-mak is-ti-jo-rum/`},{tr: `Burada bekliyorum.`, sq: `Po pres këtu.`, ipa: `/bu-ra-da bek-li-jo-rum/`},{tr: `Türkçe anlamıyorum.`, sq: `Nuk kuptoj turqisht.`, ipa: `/tyrk-çe an-la-më-jo-rum/`},{tr: `Yavaş konuşur musunuz?`, sq: `A mund të flisni ngadalë?`, ipa: `/ja-vash ko-nu-shur mu-su-nuz/`},{tr: `Size bir şey sorabilir miyim?`, sq: `A mund t’ju pyes diçka?`, ipa: `/si-ze bir shej so-ra-bi-lir mi-jim/`}], grammar: `Forma “-mek/-mak istiyorum” është çelës për të shprehur dëshira: “gitmek istiyorum”, “almak istiyorum”, “sormak istiyorum”. Për udhëtarin, kjo strukturë zëvendëson shumë gramatikë të komplikuar.`, practice: [`Thuaj “Dua të shkoj në hotel.”`,`Thuaj “Dua të blej një biletë.”`,`Thuaj “Nuk kuptoj turqisht.”`,`Kërko që dikush të flasë ngadalë.`,`Pyet nëse mund të bësh një pyetje.`]},{day: 30, title: `Përsëritje udhëtimi dhe fjali shpëtimi`, title_native: `Seyahat tekrarı ve kurtarıcı cümleler`, focus: `Ditën e fundit përmbledh frazat më të rëndësishme për udhëtim në Turqi. Qëllimi është të flasësh thjesht, qartë dhe me besim.`, vocab: [{tr: `yavaş`, sq: `ngadalë`, ipa: `/ja-vash/`},{tr: `tekrar`, sq: `përsëri`, ipa: `/tek-rar/`},{tr: `anlamıyorum`, sq: `nuk kuptoj`, ipa: `/an-la-më-jo-rum/`},{tr: `biliyorum`, sq: `e di`, ipa: `/bi-li-jo-rum/`},{tr: `bilmiyorum`, sq: `nuk e di`, ipa: `/bil-mi-jo-rum/`},{tr: `yardımcı`, sq: `ndihmues`, ipa: `/jar-dëm-xhë/`},{tr: `önemli`, sq: `e rëndësishme`, ipa: `/œ-nem-li/`},{tr: `kolay`, sq: `e lehtë`, ipa: `/ko-laj/`},{tr: `zor`, sq: `e vështirë`, ipa: `/zor/`},{tr: `güvenli`, sq: `e sigurt`, ipa: `/gy-ven-li/`}], phrases: [{tr: `Türkçe az konuşuyorum.`, sq: `Flas pak turqisht.`, ipa: `/tyrk-çe az ko-nu-shu-jo-rum/`},{tr: `Tekrar eder misiniz?`, sq: `A mund ta përsërisni?`, ipa: `/tek-rar e-der mi-si-niz/`},{tr: `Yavaş konuşur musunuz?`, sq: `A mund të flisni ngadalë?`, ipa: `/ja-vash ko-nu-shur mu-su-nuz/`},{tr: `Anlamadım.`, sq: `Nuk e kuptova.`, ipa: `/an-la-ma-dëm/`},{tr: `Bana yardım eder misiniz?`, sq: `A mund të më ndihmoni?`, ipa: `/ba-na jar-dëm e-der mi-si-niz/`},{tr: `Çok teşekkür ederim.`, sq: `Ju faleminderit shumë.`, ipa: `/çok te-shek-kyr e-de-rim/`}], grammar: `“Anlamıyorum” do të thotë “nuk kuptoj” në përgjithësi, ndërsa “anlamadım” do të thotë “nuk e kuptova” për një moment konkret. Kur nuk kupton, kombino “anlamadım” me “tekrar eder misiniz?” dhe “yavaş konuşur musunuz?”.`, practice: [`Thuaj se flet pak turqisht.`,`Kërko që dikush ta përsërisë.`,`Thuaj “Nuk e kuptova.”`,`Kërko ndihmë me “Bana yardım eder misiniz?”`,`Krijo një dialog udhëtimi me 5 fraza nga ky kurs.`]}];

var CONVERSATIONS_SQ_TR = [{id: 1, title: `Porosi në një kafene në Karaköy`, scene: `Je në një kafene të vogël në Karaköy në Stamboll. Dëshiron të porosisësh kafe turke dhe ujë, pastaj të kërkosh llogarinë.`, lines: [{who: `them`, tr: `Merhaba, ne alırsınız?`, sq: `Përshëndetje, çfarë do të merrni?`},{who: `you`, tr: `Merhaba, bir Türk kahvesi istiyorum.`, sq: `Përshëndetje, dua një kafe turke.`},{who: `them`, tr: `Şekerli mi, şekersiz mi?`, sq: `Me sheqer apo pa sheqer?`},{who: `you`, tr: `Az şekerli olsun lütfen.`, sq: `Me pak sheqer, ju lutem.`},{who: `them`, tr: `Tabii, başka bir şey ister misiniz?`, sq: `Sigurisht, a dëshironi diçka tjetër?`},{who: `you`, tr: `Bir bardak su alabilir miyim?`, sq: `A mund të marr një gotë ujë?`},{who: `them`, tr: `Elbette, hemen getiriyorum.`, sq: `Patjetër, po e sjell menjëherë.`},{who: `you`, tr: `Teşekkürler.`, sq: `Faleminderit.`},{who: `them`, tr: `Afiyet olsun.`, sq: `Ju bëftë mirë.`},{who: `you`, tr: `Hesap alabilir miyim?`, sq: `A mund të marr llogarinë?`},{who: `them`, tr: `Tabii, toplam yetmiş lira.`, sq: `Sigurisht, gjithsej shtatëdhjetë lira.`},{who: `you`, tr: `Kartla ödeyebilir miyim?`, sq: `A mund të paguaj me kartë?`}]},{id: 2, title: `Regjistrim në hotel në Kapadoki`, scene: `Mbërrin në një hotel në Göreme, Kapadoki. Ke rezervim dhe dëshiron të marrësh çelësin, fjalëkalimin e Wi-Fi dhe informacion për mëngjesin.`, lines: [{who: `them`, tr: `Merhaba, hoş geldiniz.`, sq: `Përshëndetje, mirë se erdhët.`},{who: `you`, tr: `Merhaba, rezervasyonum var.`, sq: `Përshëndetje, kam rezervim.`},{who: `them`, tr: `İsminiz nedir?`, sq: `Cili është emri juaj?`},{who: `you`, tr: `Benim adım Drita Kola.`, sq: `Emri im është Drita Kola.`},{who: `them`, tr: `Pasaportunuzu alabilir miyim?`, sq: `A mund ta marr pasaportën tuaj?`},{who: `you`, tr: `Tabii, buyurun.`, sq: `Sigurisht, ja ku është.`},{who: `them`, tr: `Odanız hazır.`, sq: `Dhoma juaj është gati.`},{who: `you`, tr: `Kahvaltı saat kaçta?`, sq: `Në ç’orë është mëngjesi?`},{who: `them`, tr: `Kahvaltı sabah sekizde başlıyor.`, sq: `Mëngjesi fillon në orën tetë.`},{who: `you`, tr: `Wi-Fi şifresi nedir?`, sq: `Cili është fjalëkalimi i Wi-Fi?`},{who: `them`, tr: `Şifre resepsiyondaki kartta yazıyor.`, sq: `Fjalëkalimi është shkruar në kartën në recepsion.`},{who: `you`, tr: `Çok teşekkür ederim.`, sq: `Ju faleminderit shumë.`}]},{id: 3, title: `Pyetje për drejtim në Taksim`, scene: `Je pranë Sheshit Taksim dhe kërkon rrugën për stacionin e metrosë. Ndalon një kalimtar dhe pyet me mirësjellje.`, lines: [{who: `you`, tr: `Merhaba, size bir şey sorabilir miyim?`, sq: `Përshëndetje, a mund t’ju pyes diçka?`},{who: `them`, tr: `Tabii, buyurun.`, sq: `Sigurisht, urdhëroni.`},{who: `you`, tr: `Metro istasyonu nerede?`, sq: `Ku është stacioni i metrosë?`},{who: `them`, tr: `Düz gidin, sonra sağa dönün.`, sq: `Shkoni drejt, pastaj kthehuni djathtas.`},{who: `you`, tr: `Kaç dakika sürer?`, sq: `Sa minuta zgjat?`},{who: `them`, tr: `Yaklaşık beş dakika sürer.`, sq: `Zgjat rreth pesë minuta.`},{who: `you`, tr: `Haritada gösterebilir misiniz?`, sq: `A mund ta tregoni në hartë?`},{who: `them`, tr: `Evet, burası istasyon.`, sq: `Po, këtu është stacioni.`},{who: `you`, tr: `Çok teşekkürler.`, sq: `Shumë faleminderit.`},{who: `them`, tr: `Rica ederim.`, sq: `Ju lutem.`},{who: `you`, tr: `İyi günler.`, sq: `Ditën e mirë.`},{who: `them`, tr: `İyi günler.`, sq: `Ditën e mirë.`}]},{id: 4, title: `Darkë në një restorant në Gaziantep`, scene: `Je në një restorant në Gaziantep dhe dëshiron të provosh ushqim lokal. Pyet për rekomandim, por nuk do që ushqimi të jetë shumë pikant.`, lines: [{who: `them`, tr: `Merhaba, kaç kişisiniz?`, sq: `Përshëndetje, sa persona jeni?`},{who: `you`, tr: `Bir kişiyim.`, sq: `Jam një person.`},{who: `them`, tr: `Buyurun, menü burada.`, sq: `Urdhëroni, menuja është këtu.`},{who: `you`, tr: `Ne önerirsiniz?`, sq: `Çfarë rekomandoni?`},{who: `them`, tr: `Bugün kebap çok güzel.`, sq: `Sot qebapi është shumë i mirë.`},{who: `you`, tr: `Acı olmasın lütfen.`, sq: `Të mos jetë pikant, ju lutem.`},{who: `them`, tr: `Tabii, az acılı yaparız.`, sq: `Sigurisht, e bëjmë pak pikant.`},{who: `you`, tr: `Bir salata da alabilir miyim?`, sq: `A mund të marr edhe një sallatë?`},{who: `them`, tr: `Elbette, içecek ister misiniz?`, sq: `Patjetër, a dëshironi pije?`},{who: `you`, tr: `Bir ayran lütfen.`, sq: `Një ajran, ju lutem.`},{who: `them`, tr: `Hemen getiriyorum.`, sq: `Po e sjell menjëherë.`},{who: `you`, tr: `Teşekkürler.`, sq: `Faleminderit.`}]},{id: 5, title: `Blerja e biletës së transportit në Stamboll`, scene: `Je në një stacion metroje në Stamboll dhe do të blesh ose mbushësh Istanbulkart. Pyet punonjësin për kartën, bilancin dhe linjën drejt Kadıköy.`, lines: [{who: `them`, tr: `Merhaba, nasıl yardımcı olabilirim?`, sq: `Përshëndetje, si mund t’ju ndihmoj?`},{who: `you`, tr: `İstanbulkart almak istiyorum.`, sq: `Dua të blej Istanbulkart.`},{who: `them`, tr: `Kart burada, bakiye yüklemek ister misiniz?`, sq: `Karta është këtu, a dëshironi të shtoni bilanc?`},{who: `you`, tr: `Evet, yüz lira yüklemek istiyorum.`, sq: `Po, dua të shtoj njëqind lira.`},{who: `them`, tr: `Nakit mi, kart mı?`, sq: `Me para në dorë apo me kartë?`},{who: `you`, tr: `Kartla ödeyebilir miyim?`, sq: `A mund të paguaj me kartë?`},{who: `them`, tr: `Evet, kart geçiyor.`, sq: `Po, karta pranohet.`},{who: `you`, tr: `Bu metro Kadıköy’e gider mi?`, sq: `A shkon kjo metro në Kadıköy?`},{who: `them`, tr: `Hayır, önce aktarma yapmanız gerekiyor.`, sq: `Jo, fillimisht duhet të ndërroni linjë.`},{who: `you`, tr: `Kaç durak sonra aktarma var?`, sq: `Pas sa stacionesh ka ndërrim?`},{who: `them`, tr: `Üç durak sonra aktarma var.`, sq: `Pas tre stacionesh ka ndërrim.`},{who: `you`, tr: `Tamam, teşekkürler.`, sq: `Në rregull, faleminderit.`}]},{id: 6, title: `Pazar në tregun lokal`, scene: `Je në një pazar në Izmir dhe dëshiron të blesh fruta. Pyet për çmimin, freskinë dhe kërkon qese në fund.`, lines: [{who: `them`, tr: `Buyurun, taze meyve var.`, sq: `Urdhëroni, ka fruta të freskëta.`},{who: `you`, tr: `Merhaba, elma kaç lira?`, sq: `Përshëndetje, sa lira kushtojnë mollët?`},{who: `them`, tr: `Kilosu kırk lira.`, sq: `Kilogrami kushton dyzet lira.`},{who: `you`, tr: `Bir kilo elma lütfen.`, sq: `Një kilogram mollë, ju lutem.`},{who: `them`, tr: `Başka bir şey ister misiniz?`, sq: `A dëshironi diçka tjetër?`},{who: `you`, tr: `Portakal taze mi?`, sq: `A janë portokallet të freskëta?`},{who: `them`, tr: `Evet, bugün geldi.`, sq: `Po, erdhën sot.`},{who: `you`, tr: `Yarım kilo portakal da istiyorum.`, sq: `Dua edhe gjysmë kilogram portokall.`},{who: `them`, tr: `Tabii, toplam altmış lira.`, sq: `Sigurisht, gjithsej gjashtëdhjetë lira.`},{who: `you`, tr: `Poşet alabilir miyim?`, sq: `A mund të marr një qese?`},{who: `them`, tr: `Elbette, buyurun.`, sq: `Patjetër, urdhëroni.`},{who: `you`, tr: `Teşekkür ederim.`, sq: `Faleminderit.`}]},{id: 7, title: `Në farmaci në Antalia`, scene: `Je në Antalia dhe të dhemb koka pas një dite të gjatë në diell. Hyn në farmaci dhe kërkon ndihmë për një ilaç pa recetë.`, lines: [{who: `them`, tr: `Merhaba, nasıl yardımcı olabilirim?`, sq: `Përshëndetje, si mund t’ju ndihmoj?`},{who: `you`, tr: `Merhaba, başım ağrıyor.`, sq: `Përshëndetje, më dhemb koka.`},{who: `them`, tr: `Ateşiniz var mı?`, sq: `A keni temperaturë?`},{who: `you`, tr: `Hayır, ateşim yok.`, sq: `Jo, nuk kam temperaturë.`},{who: `them`, tr: `Alerjiniz var mı?`, sq: `A keni alergji?`},{who: `you`, tr: `Fıstık alerjim var, ama ilaç alerjim yok.`, sq: `Kam alergji nga kikirikët, por nuk kam alergji nga ilaçet.`},{who: `them`, tr: `Reçetesiz bir ilaç verebilirim.`, sq: `Mund t’ju jap një ilaç pa recetë.`},{who: `you`, tr: `Nasıl kullanmalıyım?`, sq: `Si duhet ta përdor?`},{who: `them`, tr: `Yemekten sonra bir tablet alın.`, sq: `Merrni një tabletë pas ushqimit.`},{who: `you`, tr: `Tamam, ne kadar?`, sq: `Në rregull, sa kushton?`},{who: `them`, tr: `Seksen lira.`, sq: `Tetëdhjetë lira.`},{who: `you`, tr: `Teşekkürler.`, sq: `Faleminderit.`}]},{id: 8, title: `Bisedë e vogël në traget`, scene: `Je në tragetin nga Eminönü drejt Kadıköy. Një vendas fillon bisedë miqësore dhe ti përdor turqishten e thjeshtë për t’u përgjigjur.`, lines: [{who: `you`, tr: `Merhaba, burası boş mu?`, sq: `Përshëndetje, a është bosh ky vend?`},{who: `them`, tr: `Evet, buyurun.`, sq: `Po, urdhëroni.`},{who: `you`, tr: `Teşekkürler.`, sq: `Faleminderit.`},{who: `them`, tr: `Nerelisiniz?`, sq: `Nga jeni?`},{who: `you`, tr: `Ben Arnavutluk’tanım.`, sq: `Jam nga Shqipëria.`},{who: `them`, tr: `İstanbul’u beğendiniz mi?`, sq: `A ju pëlqeu Stambolli?`},{who: `you`, tr: `Evet, şehir çok güzel.`, sq: `Po, qyteti është shumë i bukur.`},{who: `them`, tr: `İlk kez mi geliyorsunuz?`, sq: `A vini për herë të parë?`},{who: `you`, tr: `Evet, Türkiye’ye ilk kez geliyorum.`, sq: `Po, vij në Turqi për herë të parë.`},{who: `them`, tr: `Türkçe güzel konuşuyorsunuz.`, sq: `Flisni bukur turqisht.`},{who: `you`, tr: `Teşekkürler, Türkçe az konuşuyorum.`, sq: `Faleminderit, flas pak turqisht.`},{who: `them`, tr: `Hoş geldiniz, iyi tatiller.`, sq: `Mirë se erdhët, pushime të mbara.`}]}];